class Trie {
public:
    vector<string> words;

    void insert(string word)
    {
        words.push_back(word);
    }

    bool search(string word)
    {
        for (auto &w : words) if (w == word) return true;
        return false;
    }

    bool startsWith(string prefix)
    {
        for (auto &w : words)
            if (w.size() >= prefix.size() && w.substr(0, prefix.size()) == prefix) return true;
        return false;
    }
};

