#include <iostream>
#include <vector>
#include <string>

using namespace std;

class WordDictionary {
public:
    vector<string> words;

    void addWord(string word)
    {
        words.push_back(word);
    }

    bool matches(const string &word, const string &candidate)
    {
        if (word.size() != candidate.size()) return false;
        for (int i = 0; i < (int)word.size(); i++)
            if (word[i] != '.' && word[i] != candidate[i]) return false;
        return true;
    }

    bool search(string word)
    {
        for (auto &w : words) if (matches(word, w)) return true;
        return false;
    }
};

int main()
{
    WordDictionary wd;
    wd.addWord("bad");
    wd.addWord("dad");
    wd.addWord("mad");

    cout << boolalpha << wd.search("pad") << ", ";
    cout << wd.search("bad") << ", ";
    cout << wd.search(".ad") << ", ";
    cout << wd.search("b..");

    return 0;
}

#include <iostream>
#include <string>
#include <unordered_map>

using namespace std;

struct TrieNode {
    unordered_map<char, TrieNode*> children;
    bool isEndOfWord = false;
};

class WordDictionary {
public:
    TrieNode* root;

    WordDictionary()
    {
        root = new TrieNode();
    }

    void addWord(string word)
    {
        TrieNode* node = root;
        for (char c : word)
        {
            if (node->children.find(c) == node->children.end())
                node->children[c] = new TrieNode();
            node = node->children[c];
        }
        node->isEndOfWord = true;
    }

    bool dfs(TrieNode* node, const string &word, int index)
    {
        if (node == nullptr) return false;
        if (index == (int)word.size()) return node->isEndOfWord;

        char c = word[index];
        if (c == '.')
        {
            for (auto &entry : node->children)
                if (dfs(entry.second, word, index + 1)) return true;
            return false;
        }
        else
        {
            if (node->children.find(c) == node->children.end()) return false;
            return dfs(node->children[c], word, index + 1);
        }
    }

    bool search(string word)
    {
        return dfs(root, word, 0);
    }
};

int main()
{
    WordDictionary wd;
    wd.addWord("bad");
    wd.addWord("dad");
    wd.addWord("mad");

    cout << boolalpha << wd.search("pad") << ", ";
    cout << wd.search("bad") << ", ";
    cout << wd.search(".ad") << ", ";
    cout << wd.search("b..");

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <sstream>

using namespace std;

string replaceWords(vector<string>& dictionary, string sentence)
{
    stringstream ss(sentence);
    string word;
    string result;

    while (ss >> word)
    {
        string best = word;
        for (auto &root : dictionary)
        {
            if (root.size() < best.size() && word.compare(0, root.size(), root) == 0)
                best = root;
        }
        if (!result.empty()) result += " ";
        result += best;
    }
    return result;
}

int main()
{
    vector<string> dictionary = {"cat", "bat", "rat"};
    string sentence = "the cattle was rattled by the battery";

    cout << replaceWords(dictionary, sentence);

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <sstream>
#include <unordered_map>

using namespace std;

struct TrieNode {
    unordered_map<char, TrieNode*> children;
    bool isEndOfWord = false;
};

class Trie {
public:
    TrieNode* root;

    Trie()
    {
        root = new TrieNode();
    }

    void insert(const string &word)
    {
        TrieNode* node = root;
        for (char c : word)
        {
            if (node->children.find(c) == node->children.end())
                node->children[c] = new TrieNode();
            node = node->children[c];
        }
        node->isEndOfWord = true;
    }

    string shortestRoot(const string &word)
    {
        TrieNode* node = root;
        string prefix;
        for (char c : word)
        {
            if (node->children.find(c) == node->children.end()) return word;
            prefix += c;
            node = node->children[c];
            if (node->isEndOfWord) return prefix;
        }
        return word;
    }
};

string replaceWords(vector<string>& dictionary, string sentence)
{
    Trie trie;
    for (auto &root : dictionary) trie.insert(root);

    stringstream ss(sentence);
    string word;
    string result;

    while (ss >> word)
    {
        if (!result.empty()) result += " ";
        result += trie.shortestRoot(word);
    }
    return result;
}

int main()
{
    vector<string> dictionary = {"cat", "bat", "rat"};
    string sentence = "the cattle was rattled by the battery";

    cout << replaceWords(dictionary, sentence);

    return 0;
}

