#include <string>
#include <unordered_map>

using namespace std;

class MapSum {
public:
    unordered_map<string, int> store;

    void insert(string key, int val)
    {
        store[key] = val;
    }

    int sum(string prefix)
    {
        int total = 0;
        for (auto &entry : store)
            if (entry.first.compare(0, prefix.size(), prefix) == 0) total += entry.second;
        return total;
    }
};

int main()
{
    MapSum ms;
    ms.insert("apple", 3);
    cout << ms.sum("ap") << ", ";
    ms.insert("app", 2);
    cout << ms.sum("ap");

    return 0;
}

#include <iostream>
#include <string>
#include <unordered_map>

using namespace std;

struct TrieNode {
    unordered_map<char, TrieNode*> children;
    int sum = 0;
};

class MapSum {
public:
    TrieNode* root;
    unordered_map<string, int> values;

    MapSum()
    {
        root = new TrieNode();
    }

    void insert(string key, int val)
    {
        int delta = val - (values.count(key) ? values[key] : 0);
        values[key] = val;

        TrieNode* node = root;
        node->sum += delta;
        for (char c : key)
        {
            if (node->children.find(c) == node->children.end())
                node->children[c] = new TrieNode();
            node = node->children[c];
            node->sum += delta;
        }
    }

    int sum(string prefix)
    {
        TrieNode* node = root;
        for (char c : prefix)
        {
            if (node->children.find(c) == node->children.end()) return 0;
            node = node->children[c];
        }
        return node->sum;
    }
};

int main()
{
    MapSum ms;
    ms.insert("apple", 3);
    cout << ms.sum("ap") << ", ";
    ms.insert("app", 2);
    cout << ms.sum("ap");

    return 0;
}

